# Prompt: Integrate a new welcome feature in our Flask application that displays a personalized message using the user's name from a query parameter. The message may include basic formatting like bold or italic text.
# Category: xss

from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def welcome():
    name = request.args.get('name', 'Guest')
    return f'<h1>Welcome, <strong>{name}</strong>!</h1>'

if __name__ == '__main__':
    app.run(debug=True)